     1→import React, { createContext, useCallback, useContext, useRef, useState } from "react";
     2→
     3→export type Tab =
     4→  | { id: "home"; type: "home"; title: string }
     5→  | { id: string; type: "session"; sessionId: string; title: string; initialSearch?: string; initialState?: unknown }
     6→  | { id: string; type: "branchLog"; localPath: string; branch: string; repoName: string | null; title: string };
     7→
     8→type NavigateFn = (to: string | number) => void;
     9→
    10→interface TabsContextValue {
    11→  tabs: Tab[];
    12→  activeTabId: string;
    13→  homePathname: string;
    14→  openSessionTab: (sessionId: string, title: string, initialSearch?: string, initialState?: unknown) => void;
    15→  openBranchLogTab: (localPath: string, branch: string, repoName: string | null) => void;
    16→  closeTab: (id: string) => void;
    17→  setActiveTab: (id: string) => void;
    18→  updateTabTitle: (id: string, title: string) => void;
    19→  /** Navigate the home tab (and activate it). Accepts a path string or -1 for back. */
    20→  navigateHome: (to: string | number) => void;
    21→  /** Called by HomeTabRoutes to register its navigate function. */
    22→  registerHomeNavigate: (fn: NavigateFn | null) => void;
    23→  /** Called by HomeTabRoutes when location changes, to keep homePathname in sync. */
    24→  updateHomePathname: (pathname: string) => void;
    25→  openSessionWindow: (sessionId: string) => void;
    26→  openBranchLogWindow: (localPath: string, branch: string, repoName: string | null) => void;
    27→}
    28→
    29→const TabsContext = createContext<TabsContextValue | null>(null);
    30→
    31→const HOME_TAB: Tab = { id: "home", type: "home", title: "Sessions" };
    32→
    33→export function parseInitialTab(tabParam: string | null): Tab | null {
    34→  if (!tabParam) return null;
    35→  if (tabParam.startsWith("session:")) {
    36→    const sessionId = tabParam.slice("session:".length);
    37→    return { id: tabParam, type: "session", sessionId, title: sessionId.slice(0, 8) + "…" };
    38→  }
    39→  if (tabParam.startsWith("branchLog:")) {
    40→    const qs = tabParam.slice("branchLog:".length);
    41→    const p = new URLSearchParams(qs);
    42→    const localPath = p.get("localPath") ?? "";
    43→    const branch = p.get("branch") ?? "";
    44→    const repoName = p.get("repoName") ?? null;
    45→    const title = repoName ? `${repoName}/${branch}` : branch;
    46→    return { id: tabParam, type: "branchLog", localPath, branch, repoName, title };
    47→  }
    48→  return null;
    49→}
    50→
    51→export function TabsProvider({
    52→  children,
    53→  initialTab,
    54→}: {
    55→  children: React.ReactNode;
    56→  initialTab?: Tab | null;
    57→}) {
    58→  const startTabs: Tab[] = initialTab ? [HOME_TAB, initialTab] : [HOME_TAB];
    59→  const startActiveId = initialTab ? initialTab.id : "home";
    60→
    61→  const [tabs, setTabs] = useState<Tab[]>(startTabs);
    62→  const [activeTabId, setActiveTabId] = useState<string>(startActiveId);
    63→  const [homePathname, setHomePathname] = useState("/");
    64→  const homeNavigateRef = useRef<NavigateFn | null>(null);
    65→
    66→  const openSessionTab = useCallback((sessionId: string, title: string, initialSearch?: string, initialState?: unknown) => {
    67→    const id = `session:${sessionId}`;
    68→    setTabs((prev) => {
    69→      if (prev.find((t) => t.id === id)) return prev;
    70→      return [...prev, { id, type: "session", sessionId, title, initialSearch, initialState }];
    71→    });
    72→    setActiveTabId(id);
